-- =============================================================================
-- hry_question 全量题目（15 课 × 3 题），UTF-8 编码保存。
--
-- 为何在 cmd 里粘贴后中文变 ? 或空白？
--   Windows 默认代码页是 GBK(936)，在 mysql.exe 里粘贴 UTF-8 中文会按错误字节写入。
--
-- 正确导入方式（任选其一）：
--   1) 命令行（推荐）——不要用粘贴，用文件重定向，并先切 UTF-8 代码页：
--        chcp 65001
--        mysql -u你的用户 -p --default-character-set=utf8mb4 你的库名 < seed_hry_question_full.sql
--   2) Navicat / DBeaver：打开本文件 → 运行，连接字符集选 utf8mb4；文件编码选 UTF-8。
-- =============================================================================

SET NAMES utf8mb4;

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE `hry_question`;
SET FOREIGN_KEY_CHECKS = 1;

INSERT INTO `hry_question` (`video_id`, `type`, `content`, `options`, `correct_answer`, `analysis`, `sort_order`) VALUES
(1, 'single', '【凤梨雪梨】操作前，接触水果与器具前应先完成哪一项？', '[{"key":"A","text":"洗手并消毒"},{"key":"B","text":"直接去皮"},{"key":"C","text":"先加糖"},{"key":"D","text":"先通电"}]', '"A"', '先洗手消毒可避免交叉污染，符合饮品制作卫生要求。', 1),
(1, 'multi', '【凤梨雪梨】以下哪些属于备料时常见注意事项？（多选）', '[{"key":"A","text":"水果洗净沥干"},{"key":"B","text":"生熟分开"},{"key":"C","text":"刀具与砧板混用不洗"},{"key":"D","text":"按配方称量"}]', '["A","B","D"]', '洗净沥干、生熟分开、按配方称量均为规范操作；刀具砧板混用不洗易导致交叉污染。', 2),
(1, 'judge', '【凤梨雪梨】现制饮品应在洁净操作台上完成备料与出杯。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '洁净台面可减少异物与微生物污染，判断为正确。', 3),

(2, 'single', '【牛油果草莓奶昔】使用搅拌机时，杯盖应如何操作？', '[{"key":"A","text":"盖紧并确认卡扣到位"},{"key":"B","text":"轻放即可"},{"key":"C","text":"可不盖盖短时搅拌"},{"key":"D","text":"用手按住即可"}]', '"A"', '盖紧并确认卡扣可防止溅洒与异物进入，保障安全。', 1),
(2, 'multi', '【牛油果草莓奶昔】以下哪些属于搅拌机使用安全要点？（多选）', '[{"key":"A","text":"转速由低到高逐步加"},{"key":"B","text":"杯体固定到位再启动"},{"key":"C","text":"运行中强行开盖加料"},{"key":"D","text":"异常震动立即停机检查"}]', '["A","B","D"]', '禁止运行中强行开盖；其余为安全操作要点。', 2),
(2, 'judge', '【牛油果草莓奶昔】奶昔类出品前需检查色泽与流动性是否均匀。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '均匀度影响口感与品控，判断为正确。', 3),

(3, 'single', '【牛油果雪梨】牛油果开壳后，果核处理应注意的是？', '[{"key":"A","text":"用刀固定果核旋出，避免划伤"},{"key":"B","text":"徒手硬掰"},{"key":"C","text":"直接砸桌"},{"key":"D","text":"忽略果核"}]', '"A"', '规范去核可降低划伤风险并保持果肉完整。', 1),
(3, 'multi', '【牛油果雪梨】以下哪些有助于保持牛油果风味？（多选）', '[{"key":"A","text":"选用成熟度合适果实"},{"key":"B","text":"开壳后尽快使用"},{"key":"C","text":"长时间暴露于高温日晒"},{"key":"D","text":"按标准配比与雪梨搭配"}]', '["A","B","D"]', '避免长时间高温日晒导致氧化与风味劣化。', 2),
(3, 'judge', '【牛油果雪梨】出品前需确认杯贴与订单信息一致。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '杯贴与订单一致可避免错杯，判断为正确。', 3),

(4, 'single', '【牛油果香蕉燕麦奇亚子】奇亚子使用前常需？', '[{"key":"A","text":"按配方泡发或拌入"},{"key":"B","text":"干吃硬嚼"},{"key":"C","text":"与油一起高温炸"},{"key":"D","text":"随意丢弃"}]', '"A"', '按配方处理奇亚子可保证口感与食用安全。', 1),
(4, 'multi', '【牛油果香蕉燕麦奇亚子】以下哪些属于复合饮品层次搭配要点？（多选）', '[{"key":"A","text":"注意甜度与稠度平衡"},{"key":"B","text":"颗粒感与顺滑感协调"},{"key":"C","text":"配料越多越好不论顺序"},{"key":"D","text":"按标准顺序下料"}]', '["A","B","D"]', '配料并非越多越好，顺序与比例影响最终口感。', 2),
(4, 'judge', '【牛油果香蕉燕麦奇亚子】燕麦需按门店标准煮熟或泡发后再使用。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '按标准处理燕麦可避免夹生与口感不一，判断为正确。', 3),

(5, 'single', '【牛油果鲜奶】鲜奶开封后应如何管理？', '[{"key":"A","text":"标注开封时间并冷藏先进先出"},{"key":"B","text":"常温放置即可"},{"key":"C","text":"与化学品同放"},{"key":"D","text":"不贴标签"}]', '"A"', '冷藏与先进先出可降低变质风险。', 1),
(5, 'multi', '【牛油果鲜奶】以下哪些是乳制品常见管控点？（多选）', '[{"key":"A","text":"储存温度"},{"key":"B","text":"保质期与开封时效"},{"key":"C","text":"过期仍可使用"},{"key":"D","text":"取用器具洁净"}]', '["A","B","D"]', '过期乳品不得使用。', 2),
(5, 'judge', '【牛油果鲜奶】出品前需试饮或检查风味是否异常。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '异常风味可能为变质信号，判断为正确。', 3),

(6, 'single', '【牛油果鲜橙雪梨】柑橘类榨汁或取肉时，需注意避免什么？', '[{"key":"A","text":"白色海绵层苦味过重可适当控制取肉部位"},{"key":"B","text":"连皮整块不洗"},{"key":"C","text":"与清洁剂同放"},{"key":"D","text":"不去籽"}]', '"A"', '控制白瓤与籽可减少苦涩与杂质。', 1),
(6, 'multi', '【牛油果鲜橙雪梨】以下哪些有助于提升鲜橙风味呈现？（多选）', '[{"key":"A","text":"鲜果现用"},{"key":"B","text":"按标准比例搭配雪梨"},{"key":"C","text":"使用霉变果实"},{"key":"D","text":"出杯前再轻搅避免分层过度"}]', '["A","B","D"]', '霉变果实严禁使用。', 2),
(6, 'judge', '【牛油果鲜橙雪梨】设备与容器使用后应及时清洗消毒。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '及时清洗消毒符合卫生规范，判断为正确。', 3),

(7, 'single', '【百香果雪梨】百香果开果取浆时，较稳妥的做法是？', '[{"key":"A","text":"对半切开用勺子取浆过滤籽按需"},{"key":"B","text":"整颗挤压不洗"},{"key":"C","text":"连壳打浆"},{"key":"D","text":"徒手捏爆"}]', '"A"', '对半取浆便于控制籽量与卫生。', 1),
(7, 'multi', '【百香果雪梨】以下哪些属于百香果常见品控点？（多选）', '[{"key":"A","text":"香气与酸度"},{"key":"B","text":"果壳霉变检查"},{"key":"C","text":"霉变部分挖掉继续用"},{"key":"D","text":"与雪梨甜度平衡"}]', '["A","B","D"]', '霉变果实应废弃，不得挖补使用。', 2),
(7, 'judge', '【百香果雪梨】过滤与否可按门店标准配方执行。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '是否过滤影响口感颗粒感，按标准执行即可，判断为正确。', 3),

(8, 'single', '【百香果橙】两种柑橘类搭配时，酸度调节通常优先考虑？', '[{"key":"A","text":"糖浆或标准糖酸比配方"},{"key":"B","text":"随意加水"},{"key":"C","text":"多加盐"},{"key":"D","text":"不加检测"}]', '"A"', '按配方调节糖酸比可稳定出品。', 1),
(8, 'multi', '【百香果橙】以下哪些有助于出杯外观与口感？（多选）', '[{"key":"A","text":"冰量按标准"},{"key":"B","text":"搅拌均匀度"},{"key":"C","text":"不盖杯盖防尘"},{"key":"D","text":"杯壁清洁无残留"}]', '["A","B","D"]', '出杯应盖杯盖并做好防尘。', 2),
(8, 'judge', '【百香果橙】冷冻果汁解冻后需检查是否分层异味。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '解冻品控有助于发现变质，判断为正确。', 3),

(9, 'single', '【紫甘蓝凤梨雪梨】紫甘蓝取汁或搅拌时，色泽主要来自？', '[{"key":"A","text":"天然色素，易随 pH 变化"},{"key":"B","text":"人工色素必加"},{"key":"C","text":"与盐无关"},{"key":"D","text":"高温必褪色不管"}]', '"A"', '紫甘蓝色素受酸碱影响，需按配方稳定呈现。', 1),
(9, 'multi', '【紫甘蓝凤梨雪梨】以下哪些是蔬果搭配时需关注的？（多选）', '[{"key":"A","text":"氧化与变色"},{"key":"B","text":"凤梨蛋白酶对口感影响"},{"key":"C","text":"不洗即打"},{"key":"D","text":"出杯时间"}]', '["A","B","D"]', '原料需清洗沥干再加工。', 2),
(9, 'judge', '【紫甘蓝凤梨雪梨】出品颜色应与培训标准样张大致一致。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '色差过大需复盘配方与原料批次，判断为正确。', 3),

(10, 'single', '【羽衣鲜橙雪梨】羽衣甘蓝叶片使用前通常应？', '[{"key":"A","text":"清洗沥干去老梗按量取用"},{"key":"B","text":"不洗直接使用"},{"key":"C","text":"整捆浸泡过夜不换水"},{"key":"D","text":"与肉类同案板切"}]', '"A"', '清洗沥干、去梗可减少泥沙与粗纤维。', 1),
(10, 'multi', '【羽衣鲜橙雪梨】以下哪些属于绿叶菜饮品注意点？（多选）', '[{"key":"A","text":"农药残留风险靠清洗与供应商"},{"key":"B","text":"苦涩味可用配方平衡"},{"key":"C","text":"腐烂叶继续用"},{"key":"D","text":"现打现出减少氧化"}]', '["A","B","D"]', '腐烂叶片应丢弃。', 2),
(10, 'judge', '【羽衣鲜橙雪梨】搅拌机容量不应超过最大刻度线。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '超量易导致溢出与电机负荷过大，判断为正确。', 3),

(11, 'single', '【芒果苹果雪梨】芒果取肉较常见做法是？', '[{"key":"A","text":"沿核对半划格翻起取肉"},{"key":"B","text":"带皮整颗打"},{"key":"C","text":"不去核"},{"key":"D","text":"用生锈刀"}]', '"A"', '划格取肉效率高且减少浪费。', 1),
(11, 'multi', '【芒果苹果雪梨】以下哪些会影响出杯果香？（多选）', '[{"key":"A","text":"芒果成熟度"},{"key":"B","text":"苹果氧化程度"},{"key":"C","text":"使用腐烂果"},{"key":"D","text":"搭配比例"}]', '["A","B","D"]', '腐烂果不可使用。', 2),
(11, 'judge', '【芒果苹果雪梨】易敏人群需注意门店过敏原提示。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '芒果等为常见致敏原，需按规范提示，判断为正确。', 3),

(12, 'single', '【芒果鲜奶】鲜奶与芒果泥混合时，为减少絮凝风险，通常应？', '[{"key":"A","text":"按门店标准顺序与温度操作"},{"key":"B","text":"高温久煮"},{"key":"C","text":"随意酸碱混加"},{"key":"D","text":"不搅拌"}]', '"A"', '按标准顺序与温度可减少蛋白质与酸反应导致的絮凝。', 1),
(12, 'multi', '【芒果鲜奶】以下哪些是出品质量检查项？（多选）', '[{"key":"A","text":"无异味"},{"key":"B","text":"无异常颗粒结块"},{"key":"C","text":"有霉点照常出杯"},{"key":"D","text":"甜度符合标准"}]', '["A","B","D"]', '霉点饮品不得出杯。', 2),
(12, 'judge', '【芒果鲜奶】杯身应贴合规标签含品名与时间信息（若门店要求）。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '标签有助于追溯与门店管理，判断为正确。', 3),

(13, 'single', '【芒果鲜橙雪梨】分层饮品若需保持层次，常需注意？', '[{"key":"A","text":"密度与下料顺序、冰量"},{"key":"B","text":"随意倒不分先后"},{"key":"C","text":"一次全部混合"},{"key":"D","text":"不加冰"}]', '"A"', '密度与顺序影响分层稳定性。', 1),
(13, 'multi', '【芒果鲜橙雪梨】以下哪些属于复合果饮常见步骤？（多选）', '[{"key":"A","text":"按配方分步下料"},{"key":"B","text":"尝甜补糖按标准"},{"key":"C","text":"不称量凭感觉"},{"key":"D","text":"出杯前检查容量线"}]', '["A","B","D"]', '门店出品应按配方称量，减少凭感觉。', 2),
(13, 'judge', '【芒果鲜橙雪梨】冰铲专用、不可当铲子取其他物料。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '工具专用可减少交叉污染，判断为正确。', 3),

(14, 'single', '【茫茫甘露】甘露类饮品甜度调整通常应？', '[{"key":"A","text":"按标准糖浆或配方微调并记录"},{"key":"B","text":"每杯随意加糖"},{"key":"C","text":"用口尝后加生水补满"},{"key":"D","text":"不加冰"}]', '"A"', '按标准调整可保证连锁一致性。', 1),
(14, 'multi', '【茫茫甘露】以下哪些属于常见卫生操作？（多选）', '[{"key":"A","text":"抹布分区"},{"key":"B","text":"冰铲不落地"},{"key":"C","text":"抹布擦地又擦杯口"},{"key":"D","text":"手部接触杯口需避免"}]', '["A","B","D"]', '禁止抹布混用污染杯口。', 2),
(14, 'judge', '【茫茫甘露】出杯后需检查封盖是否严密。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '封盖严密防泼洒，判断为正确。', 3),

(15, 'single', '【莲雾雪梨】莲雾清洗时较合适的做法是？', '[{"key":"A","text":"流动水冲洗轻搓沥干"},{"key":"B","text":"不洗整颗打"},{"key":"C","text":"用洗涤剂泡果不冲"},{"key":"D","text":"去蒂即可"}]', '"A"', '流动水冲洗可去除表面浮尘与部分农残。', 1),
(15, 'multi', '【莲雾雪梨】以下哪些有助于稳定口感？（多选）', '[{"key":"A","text":"原料冷藏按标准回温"},{"key":"B","text":"按配方控制冰量"},{"key":"C","text":"原料混放串味"},{"key":"D","text":"现切现打"}]', '["A","B","D"]', '原料应分开放置防串味。', 2),
(15, 'judge', '【莲雾雪梨】打烊时应按清洁计划清洗设备与台面。', '[{"key":"T","text":"正确"},{"key":"F","text":"错误"}]', 'true', '清洁计划是门店食品安全基础，判断为正确。', 3);
